parameters.jsCode:
const row = $json;
const rawPhone = String(row.phone_number || '').trim();
let phone = rawPhone.replace(/^p:/, '').trim();
if (/^52\d{10}$/.test(phone)) phone = `+${phone}`;
if (/^\d{10}$/.test(phone)) phone = `+52${phone}`;
if (!phone.startsWith('+')) phone = `+${phone.replace(/^\+/, '')}`;
const campaign = String(row.campaign_name || '').toLowerCase().trim();
const ad = String(row.ad_name || '').toLowerCase().trim();
const form = String(row.form_name || '').toLowerCase().trim();
let property = {
  property_id: 'REEMPLAZAR_PUBLIC_ID_CAUCEL',
  property_title: 'Casa en Caucel',
  property_zone: 'Caucel',
  template_name: 'caucel_info',
  template_language: 'es_MX',
  source_name: 'Facebook Lead Ads - Caucel'
};
if (campaign.includes('caucel') || ad.includes('caucel') || form.includes('caucel')) {
  property = {
    property_id: 'REEMPLAZAR_PUBLIC_ID_CAUCEL',
    property_title: 'Casa en Caucel',
    property_zone: 'Caucel',
    template_name: 'caucel_info',
    template_language: 'es_MX',
    source_name: 'Facebook Lead Ads - Caucel'
  };
}
const paymentMethod = row['¿con_qué_forma_de_pago_o_crédito_planeas_comprar?'] || row['¿cuál_es_tu_método_de_compra_o_tipo_de_crédito?'] || '';
const buyTimeline = row['¿para_cuándo_necesitas_tener_lista_tu_casa?'] || row['¿qué_tan_pronto_te_gustaría_mudarte?'] || '';
return [{
  json: {
    ...row,
    phone_clean: phone,
    payment_method: paymentMethod,
    buy_timeline: buyTimeline,
    ...property
  }
}];

const response = $json;
const contact = Array.isArray(response.payload) ? response.payload[0] : response;
const contactInboxes = Array.isArray(contact.contact_inboxes) ? contact.contact_inboxes : [];
const inbox4 = contactInboxes.find(ci => Number(ci?.inbox?.id) === 4);
return [{
  json: {
    ...$('Normalizar_y_mapear_propiedad').item.json,
    chatwoot_contact_id: contact.id || null,
    chatwoot_contact_source_id: inbox4?.source_id || null,
    chatwoot_contact_raw: contact
  }
}];

if (!$json.chatwoot_contact_id) {
  throw new Error('No se pudo obtener chatwoot_contact_id desde Chatwoot_Create_Contact');
}
if (!$json.chatwoot_contact_source_id) {
  throw new Error('No se pudo obtener chatwoot_contact_source_id del inbox 4 al crear el contacto. Revisa la respuesta de Chatwoot_Create_Contact.');
}
return [{
  json: {
    ...$json,
    chatwoot_contact_id: Number($json.chatwoot_contact_id),
    chatwoot_contact_source_id: String($json.chatwoot_contact_source_id)
  }
}];

